/* ============================================
   EDUTECH BLOGGER TEMPLATE v5
   ============================================ */

/* --- Hide skip navigation link --- */
.skip-navigation, #skip-navigation, a[href="#main"], .sb-skip-link {
  position: absolute;
  left: -9999px;
  top: -9999px;
  z-index: -1;
  opacity: 0;
  pointer-events: none;
  height: 0;
  overflow: hidden;
}

/* --- Reset --- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }
body {
  font-family: 'Open Sans', Arial, sans-serif;
  font-size: 15px;
  line-height: 1.7;
  color: #444;
  background: $(body.background.color);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  margin: 0;
  min-height: 100vh;
}
img { max-width: 100%; height: auto; }
a { color: #222; text-decoration: none; transition: color 0.25s ease; }
a:visited { color: #222; }
a:hover { color: $(keycolor); }
ul, ol { list-style: none; }
h1, h2, h3, h4, h5, h6 {
  font-family: 'Roboto', sans-serif;
  font-weight: 800;
  line-height: 1.3;
  color: #222;
}
input, button, textarea { font-family: inherit; font-size: inherit; }
button { cursor: pointer; border: none; background: none; }

/* --- Layout Mode --- */
body#layout { width: 100%; max-width: none; }
body#layout .container { width: 100%; }
body#layout .widget { width: 100%; padding: 10px; margin: 5px 0; border: 1px dashed #ccc; background: #f9f9f9; }
body#layout #home_sidebar::before {
  content: '\f015  SIDEBAR - HOME ONLY';
  display: block;
  background: #2C91E1;
  color: #fff;
  padding: 8px 14px;
  font: 700 12px/1.4 Arial, sans-serif;
  letter-spacing: 0.5px;
  border-radius: 3px;
  margin-bottom: 8px;
  font-family: 'Font Awesome 6 Free', Arial, sans-serif;
}
body#layout #post_sidebar::before {
  content: '\f15c  SIDEBAR - SINGLE POST ONLY';
  display: block;
  background: #e67e22;
  color: #fff;
  padding: 8px 14px;
  font: 700 12px/1.4 Arial, sans-serif;
  letter-spacing: 0.5px;
  border-radius: 3px;
  margin-bottom: 8px;
  font-family: 'Font Awesome 6 Free', Arial, sans-serif;
}
body#layout #sidebar_section::before {
  content: '\f0c9  SIDEBAR - ALL PAGES (except Home)';
  display: block;
  background: #27ae60;
  color: #fff;
  padding: 8px 14px;
  font: 700 12px/1.4 Arial, sans-serif;
  letter-spacing: 0.5px;
  border-radius: 3px;
  margin-bottom: 8px;
  font-family: 'Font Awesome 6 Free', Arial, sans-serif;
}
body#layout #home_sidebar,
body#layout #post_sidebar,
body#layout #sidebar_section {
  border: 2px solid #ddd;
  padding: 10px;
  margin: 10px 0;
  background: #fafafa;
  display: block !important;
  clear: both;
  width: 100% !important;
  float: none !important;
  overflow: hidden;
}
body#layout .home-two-col,
body#layout .content-layout {
  display: block !important;
}
body#layout .home-main-col,
body#layout .home-sidebar-col,
body#layout .main-content,
body#layout aside.sidebar {
  display: block !important;
  float: none !important;
  width: 100% !important;
  clear: both;
}
body#layout .cat-block,
body#layout .ad-block {
  border: 1px dashed #aaa;
  padding: 8px;
  margin: 8px 0;
  background: #f5f5f5;
}
body#layout .cat-block::before {
  content: 'Homepage Section';
  display: block;
  font: 700 10px/1.5 Arial, sans-serif;
  color: #999;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}
body#layout .ad-block::before {
  content: 'Ad Block';
  display: block;
  font: 700 10px/1.5 Arial, sans-serif;
  color: #e67e22;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}
body#layout #cat_section_1::before { content: 'Category Section 1 (Entertainment)'; display: block; font: 700 10px/1.5 Arial; color: #2c91e1; }
body#layout #cat_section_2::before { content: 'Category Section 2 (Fun & Fashion)'; display: block; font: 700 10px/1.5 Arial; color: #2c91e1; }
body#layout #cat_section_3::before { content: 'Category Section 3 (International)'; display: block; font: 700 10px/1.5 Arial; color: #2c91e1; }

/* --- Container --- */
.container { max-width: $(content.width); margin: 0 auto; padding: 0 15px; }

/* ============================================
   TOP BAR
   ============================================ */
.top-bar {
  background: #222;
  color: #fff;
  overflow: hidden;
}
.top-bar .container {
  display: flex;
  align-items: center;
  height: 40px;
}
.headline-left {
  display: flex;
  align-items: center;
  flex: 1;
  overflow: hidden;
  height: 40px;
}
.headline-label {
  background: $(keycolor);
  color: #fff;
  padding: 0 12px;
  font-size: 11px;
  font-weight: 700;
  white-space: nowrap;
  height: 26px;
  line-height: 26px;
  flex-shrink: 0;
  border-radius: 3px;
  margin-right: 12px;
  text-transform: uppercase;
  font-family: 'Roboto', sans-serif;
  letter-spacing: 0.5px;
}
.headline-ticker {
  overflow: hidden;
  white-space: nowrap;
  flex: 1;
  height: 40px;
  line-height: 40px;
}
.headline-ticker .ticker-wrap {
  display: inline-block;
  animation: ticker 25s linear infinite;
}
.headline-ticker a {
  color: #bbb;
  font-size: 13px;
  font-family: 'Open Sans', sans-serif;
  padding: 0 20px;
  display: inline-block;
}
.headline-ticker a:hover, .headline-ticker a:visited:hover { color: #fff; }
@keyframes ticker {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}
.topbar-right {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
  margin-left: 15px;
}
.topbar-right .follow-text {
  color: #999;
  font-size: 11px;
  white-space: nowrap;
  margin-right: 6px;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.topbar-right .top-social a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 26px; height: 26px;
  background: #444;
  border-radius: 50%;
  color: #fff;
  font-size: 11px;
  transition: background 0.3s;
}
.topbar-right .top-social a:hover, .topbar-right .top-social a:visited:hover { background: $(keycolor); color: #fff; }
.topbar-right .top-search-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 26px; height: 26px;
  background: $(keycolor);
  border-radius: 50%;
  color: #fff;
  font-size: 11px;
  cursor: pointer;
  border: none;
  margin-left: 4px;
}
.top-search-box {
  display: none;
  position: absolute;
  right: 10px;
  top: 40px;
  background: #fff;
  padding: 10px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.15);
  z-index: 9999;
  border-radius: 3px;
}
.top-search-box.active { display: block; }
.top-search-box input {
  border: 1px solid #ddd;
  padding: 8px 14px;
  font-size: 14px;
  width: 240px;
  outline: none;
  border-radius: 3px;
}

/* ============================================
   HEADER
   ============================================ */
.header-wrapper {
  background: #fff;
  position: relative;
  z-index: 1000;
}
.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 0;
}
.site-logo {
  float: left;
  max-width: 350px;
  text-align: left;
}
.site-logo h1 {
  font: $(blog.title.font);
  color: $(blog.title.color);
  margin: 5px 5px 0;
  text-transform: none;
}
.site-logo h1 a { color: $(blog.title.color); }
.site-logo h1 a:hover { color: $(keycolor); }
.site-logo p.description {
  font-size: 13px;
  color: #888;
  margin: 2px 5px 0;
  line-height: 1.2;
  font-family: 'Open Sans', sans-serif;
}
.header-ad {
  float: right;
  max-width: 728px;
}

/* ============================================
   NAVIGATION
   ============================================ */
.topbar-nav {
  background: #fff;
  border-top: 1px solid #eee;
  border-bottom: 2px solid $(keycolor);
  height: auto;
  z-index: 999;
  position: relative;
}
.topbar-nav .container {
  display: flex;
  align-items: center;
}
.main-nav { flex: 1; }
.main-nav ul {
  display: flex;
  align-items: center;
  gap: 0;
  margin: 0;
  padding: 0;
  height: 44px;
}
.main-nav ul li { position: relative; list-style: none; }
.main-nav ul li a {
  display: block;
  line-height: 44px;
  padding: 0 18px;
  font-size: 13px;
  font-weight: 700;
  font-family: 'Roboto', sans-serif;
  color: #333;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  transition: all 0.25s ease;
  border-bottom: 2px solid transparent;
  margin-bottom: -2px;
}
.main-nav ul li a:hover,
.main-nav ul li a:visited:hover {
  color: $(keycolor);
  border-bottom-color: $(keycolor);
}
.main-nav ul li.selected a,
.main-nav ul li.home a {
  color: $(keycolor);
  border-bottom-color: $(keycolor);
}
.main-nav ul li ul {
  display: none;
  position: absolute;
  top: 44px;
  left: 0;
  background: #fff;
  min-width: 200px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.12);
  z-index: 1000;
  flex-direction: column;
  height: auto;
  border-top: 2px solid $(keycolor);
}
.main-nav ul li:hover > ul { display: flex; }
.main-nav ul li ul li a {
  line-height: 40px;
  padding: 0 18px;
  font-size: 12px;
  font-weight: 600;
  border-bottom: 1px solid #f0f0f0;
  margin-bottom: 0;
}
.main-nav ul li ul li a:hover { background: #f7f7f7; color: $(keycolor); border-bottom-color: #f0f0f0; }
.main-nav ul li.has-sub > a::after {
  content: ' \f107';
  font-family: 'Font Awesome 6 Free';
  font-weight: 900;
  font-size: 10px;
  margin-left: 4px;
}
.mobile-menu-toggle {
  display: none;
  font-size: 22px;
  color: #333;
  padding: 8px;
  line-height: 44px;
}
.slicknav_menu { display: none; }

/* ============================================
   FEATURED SLIDER + 2x2 GRID
   ============================================ */
.featured-section {
  padding: 18px 0 10px;
  background: $(body.background.color);
}
.featured-layout {
  display: flex;
  gap: 4px;
}
.featured-slider {
  width: 50%;
  position: relative;
  overflow: hidden;
}
.featured-slider .slide-item {
  position: relative;
  background: #000;
}
.featured-slider .slide-item img {
  display: block;
  width: 100%;
  height: 432px;
  object-fit: cover;
}
.featured-slider .slide-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 40px 25px 25px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.75) 100%);
  color: #fff;
}
.featured-slider .slide-cat {
  display: inline-block;
  padding: 3px 10px;
  background: $(keycolor);
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  border-radius: 3px;
  margin-bottom: 8px;
  font-family: 'Roboto', sans-serif;
}
.featured-slider .slide-cat:visited { color: #fff; }
.featured-slider .slide-title a {
  color: #fff;
  font-size: 18px;
  font-weight: 800;
  line-height: 1.35;
  display: block;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
}
.featured-slider .slide-title a:visited { color: #fff; }
.featured-slider .slide-title a:hover { color: #ddd; }
.featured-slider .slide-meta {
  font-size: 12px;
  color: #ccc;
  margin-top: 6px;
  font-family: 'Open Sans', sans-serif;
}
.featured-slider .slide-meta span { margin-right: 12px; }
.featured-slider .slick-prev,
.featured-slider .slick-next {
  border-radius: 3px;
  top: 12px;
  z-index: 999;
  width: 24px;
  height: 24px;
  background-color: rgba(255,255,255,0.9);
}
.featured-slider .slick-next { right: 6px; }
.featured-slider .slick-prev { right: 34px; left: auto; }
.featured-slider .slick-prev:before {
  content: '\f104';
  font-family: 'Font Awesome 6 Free';
  font-weight: 900;
  color: #000;
  font-size: 12px;
  line-height: 1;
}
.featured-slider .slick-next:before {
  content: '\f105';
  font-family: 'Font Awesome 6 Free';
  font-weight: 900;
  color: #000;
  font-size: 12px;
  line-height: 1;
}
.featured-grid {
  width: 50%;
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: 1fr 1fr;
  gap: 4px;
}
.featured-grid-card {
  position: relative;
  overflow: hidden;
  background: #000;
}
.featured-grid-card img {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
  min-height: 214px;
  opacity: 0.85;
  transition: opacity 0.3s;
}
.featured-grid-card:hover img { opacity: 0.65; }
.featured-grid-card .grid-card-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 12px 14px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.7) 100%);
  color: #fff;
}
.featured-grid-card .grid-card-cat {
  display: inline-block;
  padding: 2px 8px;
  background: $(keycolor);
  color: #fff;
  font-size: 9px;
  font-weight: 700;
  text-transform: uppercase;
  border-radius: 3px;
  margin-bottom: 4px;
  font-family: 'Roboto', sans-serif;
}
.featured-grid-card .grid-card-cat:visited { color: #fff; }
.featured-grid-card .grid-card-title a {
  color: #fff;
  font-size: 13px;
  font-weight: 800;
  line-height: 1.3;
  display: block;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
}
.featured-grid-card .grid-card-title a:visited { color: #fff; }
.featured-grid-card .grid-card-title a:hover { color: #ddd; }

/* ============================================
   SECTION TITLES (Pill Style)
   ============================================ */
.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 15px;
  padding-bottom: 0;
  border-bottom: none;
}
.section-header::after { display: none; }
.section-title {
  background: $(keycolor);
  margin-bottom: 0;
  padding: 5px 16px;
  color: #fff;
  display: inline-block;
  border-radius: 3px;
  text-transform: capitalize;
  font-size: 12px;
  line-height: 20px;
  font-family: 'Roboto', sans-serif;
  font-weight: 700;
  letter-spacing: 0.5px;
}

/* ============================================
   MAIN 2-COLUMN LAYOUT (Content + Sidebar continuous)
   After featured section, everything is in one flex row
   ============================================ */
.home-body {
  padding: 15px 0 0;
}
.home-two-col {
  display: flex;
  gap: 25px;
}
.home-main-col {
  flex: 1;
  min-width: 0;
}
.home-sidebar-col {
  width: 300px;
  flex-shrink: 0;
}

/* Category section spacing inside main col */
.cat-block {
  margin-bottom: 25px;
}

/* Ad insertion block */
.ad-block {
  margin: 20px 0;
  text-align: center;
}

/* Entertainment: Big card + small list */
.cat-entertainment-layout {
  display: flex;
  gap: 10px;
}
.cat-big-card {
  width: 50%;
  position: relative;
  overflow: hidden;
  background: #000;
  border-radius: 4px;
}
.cat-big-card img {
  display: block;
  width: 100%;
  height: 100%;
  min-height: 280px;
  object-fit: cover;
}
.cat-big-card .cat-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 20px 20px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.75) 100%);
  color: #fff;
}
.cat-big-card .cat-title a {
  color: #fff;
  font-size: 15px;
  font-weight: 800;
  text-transform: uppercase;
  line-height: 1.35;
  font-family: 'Roboto', sans-serif;
}
.cat-big-card .cat-title a:visited { color: #fff; }
.cat-big-card .cat-summary {
  font-size: 12px;
  color: #ddd;
  margin-top: 6px;
  line-height: 1.5;
  font-family: 'Open Sans', sans-serif;
}
.cat-big-card .cat-meta {
  font-size: 11px;
  color: #bbb;
  margin-top: 6px;
  font-family: 'Open Sans', sans-serif;
}
.cat-small-list {
  width: 50%;
}
.cat-small-item {
  display: flex;
  gap: 10px;
  padding: 8px 0;
  border-bottom: 1px solid #eee;
  align-items: flex-start;
}
.cat-small-item:last-child { border-bottom: none; }
.cat-small-item .item-thumb {
  flex-shrink: 0;
  width: 90px;
  height: 68px;
  overflow: hidden;
  border-radius: 3px;
}
.cat-small-item .item-thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.cat-small-item .item-info { flex: 1; }
.cat-small-item .item-title a {
  font-size: 13px;
  font-weight: 800;
  color: #222;
  text-transform: uppercase;
  line-height: 1.35;
  display: block;
  font-family: 'Roboto', sans-serif;
}
.cat-small-item .item-title a:hover { color: $(keycolor); }
.cat-small-item .item-meta {
  font-size: 11px;
  color: #999;
  margin-top: 4px;
  font-family: 'Open Sans', sans-serif;
}
.cat-small-item .item-meta i { color: $(keycolor); margin-right: 3px; }

/* Fun & Fashion: 2 rows (3+2 or 3+3) grid with big first card */
#cat_section_2 .widget { margin-bottom: 25px; }
#cat_section_2 .widget:last-child { margin-bottom: 0; }
.cat-ff-layout {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 6px;
}
.cat-ff-card {
  position: relative;
  overflow: hidden;
  background: #000;
  border-radius: 4px;
}
.cat-ff-card img {
  display: block;
  width: 100%;
  height: 200px;
  object-fit: cover;
  transition: opacity 0.3s;
}
.cat-ff-card:hover img { opacity: 0.7; }
.cat-ff-card .ff-card-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 12px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.7) 100%);
  color: #fff;
}
.cat-ff-card .ff-card-title a {
  color: #fff;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
  line-height: 1.3;
  font-family: 'Roboto', sans-serif;
}
.cat-ff-card .ff-card-title a:visited { color: #fff; }
.cat-ff-card .ff-card-meta {
  font-size: 10px;
  color: #ccc;
  margin-top: 3px;
  font-family: 'Open Sans', sans-serif;
}
.cat-ff-card .ff-card-meta a { color: #ccc; }
.cat-ff-card .ff-card-meta a:hover { color: #fff; }

/* International: Slider cards */
.cat-slider-wrap { position: relative; }
.cat-slider-card {
  position: relative;
  overflow: hidden;
  background: #000;
  border-radius: 4px;
  margin: 0 4px;
}
.cat-slider-card img {
  display: block;
  width: 100%;
  height: 220px;
  object-fit: cover;
  transition: opacity 0.3s;
}
.cat-slider-card:hover img { opacity: 0.7; }
.cat-slider-card .slider-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 14px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.7) 100%);
  color: #fff;
}
.cat-slider-card .slider-title a {
  color: #fff;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
  line-height: 1.3;
  font-family: 'Roboto', sans-serif;
}
.cat-slider-card .slider-title a:visited { color: #fff; }
.cat-slider-card .slider-meta {
  font-size: 10px;
  color: #ccc;
  margin-top: 3px;
  font-family: 'Open Sans', sans-serif;
}
.cat-slider-card .slider-meta a { color: $(keycolor); font-weight: 600; }
.cat-slider-card .slider-meta a:hover { color: #fff; }
.cat-slider-wrap .slick-prev,
.cat-slider-wrap .slick-next {
  border-radius: 50%;
  z-index: 999;
  width: 28px;
  height: 28px;
  background-color: rgba(255,255,255,0.9);
  top: 50%;
  transform: translateY(-50%);
}
.cat-slider-wrap .slick-next { right: 6px; }
.cat-slider-wrap .slick-prev { left: 6px; }
.cat-slider-wrap .slick-prev:before {
  content: '\f104';
  font-family: 'Font Awesome 6 Free';
  font-weight: 900;
  color: #000;
  font-size: 13px;
}
.cat-slider-wrap .slick-next:before {
  content: '\f105';
  font-family: 'Font Awesome 6 Free';
  font-weight: 900;
  color: #000;
  font-size: 13px;
}

/* ============================================
   LATEST UPDATES (JS-loaded)
   ============================================ */
.latest-post-item {
  border-bottom: 1px solid #eee;
  padding: 15px 0;
  display: flex;
  gap: 18px;
}
.latest-post-item:last-child { border-bottom: none; }
.latest-post-thumb {
  flex-shrink: 0;
  width: 100%;
  max-width: 280px;
  overflow: hidden;
  border-radius: 4px;
}
.latest-post-thumb img {
  display: block;
  width: 100%;
  height: 170px;
  object-fit: cover;
}
.latest-post-info { flex: 1; min-width: 0; }
.latest-post-info .lp-title {
  font-size: 18px;
  font-weight: 800;
  font-family: 'Roboto', sans-serif;
  line-height: 1.35;
  margin-bottom: 6px;
  text-transform: uppercase;
}
.latest-post-info .lp-title a { color: #222; }
.latest-post-info .lp-title a:hover { color: $(keycolor); }
.latest-post-info .lp-meta {
  font-size: 12px;
  color: #888;
  margin-bottom: 8px;
  font-family: 'Open Sans', sans-serif;
}
.latest-post-info .lp-meta a { color: $(keycolor); }
.latest-post-info .lp-meta .ppi-dot { margin: 0 6px; color: #ccc; }
.latest-post-info .lp-summary {
  font-size: 14px;
  color: #555;
  line-height: 1.65;
  font-family: 'Open Sans', sans-serif;
}
.latest-post-info .lp-readmore {
  display: inline-block;
  margin-top: 8px;
  background: #222;
  color: #fff;
  padding: 5px 14px;
  font-size: 11px;
  font-weight: 700;
  border-radius: 3px;
  transition: 0.2s;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.3px;
}
.latest-post-info .lp-readmore:visited { color: #fff; }
.latest-post-info .lp-readmore:hover { background: $(keycolor); }
.load-more-wrap {
  text-align: center;
  padding: 20px 0;
}
.page-numbers {
  display: inline-block;
  padding: 6px 12px;
  margin: 0 3px;
  background: #fff;
  border: 1px solid #ddd;
  color: #333;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: 0.2s;
  font-family: 'Roboto', sans-serif;
}
.page-numbers:hover, .page-numbers.active {
  background: $(keycolor);
  color: #fff;
  border-color: $(keycolor);
}

/* ============================================
   NON-HOME CONTENT + SIDEBAR
   ============================================ */
.content-wrapper { padding: 20px 0; }
.content-layout {
  display: flex;
  gap: 25px;
}
.main-content {
  flex: 1;
  min-width: 0;
  padding: 0 15px;
}
/* Single post: center content with readable width */
.item-view .main-content {
  max-width: 820px;
}

/* Blog Posts */
.Blog .blog-posts .post-outer-container {
  background: $(posts.background.color);
  border-bottom: 1px solid #eee;
  overflow: hidden;
  margin-bottom: 20px;
  padding: 0 0 20px 0;
}
.Blog .blog-posts .post-outer-container .post-outer {
  border: 0;
  position: relative;
  padding: 0;
}
.post-title {
  font: $(posts.title.font);
  margin: 15px 0 10px 0;
  padding: 0;
  font-size: 24px;
  line-height: 1.4em;
  color: #222;
}
.post-title a, .post-title a:visited {
  color: #222;
  text-decoration: none;
  font-weight: 800;
}
.post-title a:hover { color: $(keycolor); }
.post-body {
  color: $(posts.text.color);
  font: $(posts.text.font);
  line-height: 1.75;
  letter-spacing: 0.2px;
  margin: 10px 0 15px 0;
}
.post-body img { margin: 10px 0; }
.post-body a { color: $(keycolor); }
.post-body blockquote {
  font-size: 14px;
  padding: 15px 20px;
  margin: 20px 0;
  background: #f7f7f7;
  border-left: 3px solid $(keycolor);
  font-style: italic;
}
.post-body h2, .post-body h3 { margin: 24px 0 12px; }
.post-body p { margin-bottom: 16px; }
.snippet-thumbnail {
  float: $(startSide);
  margin: 0;
  margin-$endSide: 2em;
  max-height: 128px;
  max-width: 128px;
}
.snippet-thumbnail img { max-width: 100%; }
.byline {
  color: $(posts.byline.color);
  display: inline-block;
  line-height: 24px;
  margin-top: 8px;
  margin-$endSide: 1em;
  font-size: 13px;
  font-family: 'Open Sans', sans-serif;
}
.byline:last-child { margin-$endSide: 0; }
.byline a { color: $(posts.byline.color); }
.byline a:hover { color: $(keycolor); }
.jump-link { display: inline-block; margin-top: 12px; }
.jump-link a {
  background-color: #222;
  display: inline-block;
  padding: 5px 14px;
  color: #fff;
  transition: 0.2s;
  font-size: 11px;
  font-weight: 700;
  border-radius: 3px;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
}
.jump-link a:visited { color: #fff; }
.jump-link a:hover { background: $(keycolor); color: #fff; }
.post-footer, .post-header {
  clear: $(startSide);
  color: $(posts.byline.color);
  margin: 0;
}
.post-bottom {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
}
.blog-pager {
  text-align: center;
  margin: 2em 0;
}
.blog-pager a {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 16px;
  background: #fff;
  border: 1px solid #ddd;
  font-size: 14px;
  font-weight: 600;
  color: #333;
  transition: all 0.25s ease;
  border-radius: 3px;
}
.blog-pager a:hover {
  background: $(keycolor);
  color: #fff;
  border-color: $(keycolor);
}
.byline.post-labels a {
  background: #222;
  color: #fff;
  float: left;
  font-family: 'Roboto', sans-serif;
  font-size: 11px;
  margin: 0 4px 4px 0;
  padding: 3px 8px;
  border-radius: 3px;
  transition: all 0.25s ease;
}
.byline.post-labels a:hover { background: $(keycolor); color: #fff; }
/* Hide Blogger's default breadcrumb (HOME link below nav) */
.breadcrumbs, .breadcrumb, #breadcrumb,
.blog-post-breadcrumb, .post-filter-message,
.hierarchy, .blog-posts .breadcrumbs,
.blog-content .breadcrumbs,
.post-outer .breadcrumbs,
.flat-icon-button.breadcrumbs,
.post-outer > nav,
.byline.breadcrumb,
.blog-post .breadcrumb,
.blog-pager-container nav,
.post-outer-container > nav,
.Blog nav.breadcrumb,
.Blog .breadcrumbs,
.Blog nav[aria-label],
.post-title-container .breadcrumbs { display: none !important; }
/* Also hide the single HOME link breadcrumb that Blogger renders */
.main-content > nav:first-child,
#main-content > nav:first-child,
.blog-posts > nav:first-child { display: none !important; }

/* Custom breadcrumb for single post */
.custom-breadcrumb {
  font-size: 13px;
  font-family: 'Open Sans', sans-serif;
  color: #999;
  padding: 12px 0 8px;
  margin-bottom: 5px;
}
.custom-breadcrumb a {
  color: $(keycolor);
  text-decoration: none;
}
.custom-breadcrumb a:hover {
  text-decoration: underline;
}
.custom-breadcrumb .sep {
  margin: 0 6px;
  color: #999;
}
.custom-breadcrumb .current {
  color: #999;
}

/* Hide Blogger's default share buttons (black share icon) */
.post-share-buttons { display: none !important; }
.share-buttons { display: none !important; }
.sharing { display: none !important; }
.post-share-buttons-top { display: none !important; }
.post-share-buttons-bottom { display: none !important; }
.flat-button.share-button { display: none !important; }
.post-header .share-button { display: none !important; }
div[class*='share'] img[src*='share'] { display: none !important; }

/* Custom Share Buttons */
.custom-share-buttons {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 18px 0;
  padding: 14px 0;
  border-top: 1px solid #eee;
  border-bottom: 1px solid #eee;
  flex-wrap: wrap;
}
.custom-share-buttons .share-label {
  font-size: 12px;
  font-weight: 700;
  color: #555;
  font-family: 'Roboto', sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-right: 4px;
}
.share-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  color: #fff !important;
  font-size: 15px;
  transition: opacity 0.25s ease;
}
.share-btn:visited { color: #fff !important; }
.share-btn:hover { opacity: 0.8; color: #fff !important; }
.share-fb { background: #1877F2; }
.share-tw { background: #000; }
.share-wa { background: #25D366; }
.share-tg { background: #0088cc; }

/* Comments */
#comments {
  border-top: 1px dashed rgba(0,0,0,0.12);
  margin-top: 20px;
  padding: 20px;
}
#comments .comment-thread ol { margin: 0; padding-left: 0; }
#comments .comment { list-style-type: none; padding: 0 0 20px; position: relative; }
.comment .avatar-image-container { position: absolute; }
.comment .avatar-image-container img { border-radius: 50%; }
.comment .comment-block {
  margin-top: 10px;
  margin-$startSide: 60px;
  padding: 16px;
  background: #ffffff;
  border: 1px solid #eee;
  border-radius: 4px;
}
#comments .comment .comment-header .user,
#comments .comment .comment-header .user a {
  color: #222;
  font-weight: 700;
  font-size: 14px;
}
#comments .comment .comment-header .datetime {
  color: #9CA3AF;
  font-size: 12px;
  font-style: italic;
  margin-$startSide: 8px;
}
#comments .comment .comment-content { margin-top: 8px; font-size: 14px; line-height: 1.7; }

/* Status Messages */
.no-posts-message { line-height: 40px; text-align: center; }
.status-msg-wrap, .post-filter-message {
  margin: 16px 0;
  padding: 12px 16px;
  background: #FEF3C7;
  border: 1px solid #F59E0B;
  border-radius: 5px;
  color: #92400E;
  font-size: 14px;
}

/* ============================================
   SIDEBAR
   ============================================ */
.sidebar {
  width: 300px;
  min-width: 300px;
  word-wrap: break-word;
}
.sidebar .widget {
  background: $(sidebar.background.color);
  margin: 0 0 1.5em;
  padding: 0 0 1.5em;
}
.sidebar .widget .title,
.sidebar .widget h2,
.sidebar .widget h3.title,
.sidebar .widget h3 {
  background: $(keycolor);
  margin-bottom: 12px;
  padding: 5px 14px;
  color: $(widget.title.color);
  display: inline-block;
  border-radius: 3px;
  text-transform: capitalize;
  font-size: 12px;
  line-height: 20px;
  font-family: 'Roboto', sans-serif;
  font-weight: 700;
  letter-spacing: 0.5px;
  border-bottom: none;
  position: relative;
}
.sidebar .widget .title::after,
.sidebar .widget h2::after,
.sidebar .widget h3::after { display: none; }

/* Popular Posts */
.sidebar .PopularPosts ul { list-style: none; padding: 0; margin: 0; }
.sidebar .PopularPosts .post {
  display: block;
  position: relative;
  overflow: hidden;
  border-radius: 4px;
  margin-bottom: 12px;
  background: #000;
}
.sidebar .PopularPosts .post:last-child { margin-bottom: 0; }
.sidebar .PopularPosts .item-thumbnail {
  display: block;
  width: 100%;
  height: auto;
  overflow: hidden;
}
.sidebar .PopularPosts .item-thumbnail img {
  display: block;
  width: 100%;
  height: 180px;
  object-fit: cover;
  transition: opacity 0.3s;
}
.sidebar .PopularPosts .post:hover .item-thumbnail img { opacity: 0.7; }
.sidebar .PopularPosts .item-content {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  padding: 14px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.75) 100%);
}
.sidebar .PopularPosts .post-title a,
.sidebar .PopularPosts h3.post-title a {
  font: 800 13px/1.4 'Roboto', sans-serif;
  text-transform: uppercase;
  letter-spacing: 0.2px;
  color: #fff;
}
.sidebar .PopularPosts .post-title a:hover { color: #ddd; }
.sidebar .PopularPosts .item-snippet { display: none; }

/* Labels */
.sidebar .Label ul { list-style: none; padding: 0; margin: 0; }
.sidebar .Label li {
  border-bottom: 1px dotted #eee;
  line-height: 34px;
  font-family: 'Open Sans', sans-serif;
  padding: 0 10px;
}
.sidebar .Label li:last-child { border-bottom: none; }
.sidebar .Label a {
  font-size: 13px;
  color: #444;
  font-weight: 600;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.sidebar .Label a:hover { color: $(keycolor); }
.label-count { color: #9CA3AF; font-size: 12px; }
.Label .label-count::before { content: "("; }
.Label .label-count::after { content: ")"; }

/* Cloud Labels */
.cloud-label-widget-content li,
.cloud-label-widget-content a {
  background: #222;
  color: #fff;
  float: left;
  font-family: 'Roboto', sans-serif;
  font-size: 12px;
  margin: 0 4px 4px 0;
  padding: 2px 8px;
  text-decoration: none;
  transition: all 0.25s ease;
  border-radius: 3px;
}
.cloud-label-widget-content a:hover { background: $(keycolor); color: #fff; }

/* Social Icons */
.social-icons a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px; height: 36px;
  background: #333;
  border-radius: 50%;
  color: #fff;
  margin: 0 4px 4px 0;
  font-size: 14px;
  transition: all 0.25s ease;
  border: none;
}
.social-icons a:hover, .social-icons a:visited:hover {
  background: $(keycolor);
  color: #fff;
}

/* Featured Post widget */
.sidebar .FeaturedPost .snippet-thumbnail { float: none; margin: 0 0 10px 0; max-width: 100%; max-height: none; }
.sidebar .FeaturedPost .snippet-thumbnail img { width: 100%; border-radius: 4px; }

.collapsible > summary { cursor: pointer; display: block; padding: 0; }
.collapsible > summary::-webkit-details-marker { display: none; }

/* ============================================
   FOOTER
   ============================================ */
#main-footer {
  background: #ffffff;
  border-top: 1px solid #e5e5e5;
  color: #555;
  padding: 35px 0 0;
  margin-top: 20px;
}
.footer-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
}
.footer-col .widget {
  background: transparent;
  border: none;
  padding: 0;
}
.footer-col h3, .footer-col h2 {
  font-weight: 600;
  font-size: 16px;
  font-family: 'Roboto', sans-serif;
  color: #333;
  margin-bottom: 15px;
  padding-bottom: 10px;
  border-bottom: 1px solid #ddd;
}
.footer-col p, .footer-col li {
  font-size: 14px;
  color: #666;
  line-height: 1.8;
  font-family: 'Open Sans', sans-serif;
}
.footer-col a { color: #555; }
.footer-col a:hover { color: $(keycolor); }
.footer-col ul { list-style: none; padding: 0; margin: 0; }
.footer-col ul li { padding: 4px 0; }
.footer-bottom {
  text-align: center;
  padding: 14px 0;
  margin-top: 25px;
  background: $(keycolor);
  font-size: 13px;
  color: #fff;
  font-family: 'Open Sans', sans-serif;
  letter-spacing: 0.3px;
}
.footer-bottom a { color: #fff; font-weight: 600; }
.footer-bottom a:hover { text-decoration: underline; color: #fff; }

.Attribution { text-align: center; font-size: 13px; color: #777; }
.Attribution a { color: #555; }

/* ============================================
   SCROLL TO TOP
   ============================================ */
.back-to-top {
  position: fixed;
  bottom: 50px;
  right: 25px;
  width: 42px;
  height: 42px;
  background: $(keycolor);
  color: #fff;
  border-radius: 50%;
  display: none;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  cursor: pointer;
  z-index: 9999;
  line-height: 42px;
  text-align: center;
  transition: all 0.25s ease;
  border: none;
  box-shadow: 0 2px 8px rgba(0,0,0,0.15);
}
.back-to-top:hover { opacity: 0.85; }

/* 404 */
.error-404 {
  text-align: center;
  padding: 80px 20px;
}
.error-404 h1 { font-size: 6rem; color: $(keycolor); font-weight: 800; }
.error-404 h2 { font-size: 1.5rem; margin-bottom: 16px; }
.error-404 p { color: #6B7280; margin-bottom: 24px; }
.error-404 a.btn {
  display: inline-block;
  padding: 12px 30px;
  background: $(keycolor);
  color: #fff;
  border-radius: 3px;
  font-weight: 700;
}
.error-404 a.btn:visited { color: #fff; }

/* ============================================
   RESPONSIVE
   ============================================ */
@media (max-width: 1024px) {
  .content-layout { flex-direction: column; }
  .home-two-col { flex-direction: column; }
  .home-sidebar-col { width: 100%; min-width: 0; }
  .main-content { width: 100%; }
  .sidebar { width: 100%; min-width: 0; }
  .featured-layout { flex-direction: column; }
  .featured-slider { width: 100%; }
  .featured-grid { width: 100%; }
  .featured-grid-card img { min-height: 180px; }
  .cat-entertainment-layout { flex-direction: column; }
  .cat-big-card { width: 100%; }
  .cat-small-list { width: 100%; }
  .cat-ff-layout { grid-template-columns: repeat(2, 1fr); }
  .footer-grid { grid-template-columns: repeat(2, 1fr); }
  .latest-post-item { flex-direction: column; }
  .latest-post-thumb { max-width: 100%; }
}

@media (max-width: 768px) {
  .main-nav { display: none; }
  .mobile-menu-toggle { display: block; }
  .slicknav_menu { display: block; }
  .topbar-right { display: none; }
  .featured-slider .slide-item img { height: 280px; }
  .featured-grid { grid-template-columns: 1fr 1fr; }
  .cat-ff-layout { grid-template-columns: repeat(2, 1fr); }
  .footer-grid { grid-template-columns: 1fr; }
}

@media (max-width: 480px) {
  .featured-slider .slide-item img { height: 220px; }
  .featured-grid { grid-template-columns: 1fr; }
  .cat-ff-layout { grid-template-columns: 1fr; }
  .container { padding: 0 10px; }
}

/* Related Articles */
.related-articles { margin-top: 25px; padding-top: 20px; border-top: 1px solid #eee; }
.related-articles .section-header { margin-bottom: 15px; }
.related-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
}
.related-card {
  position: relative;
  overflow: hidden;
  background: #000;
  border-radius: 4px;
}
.related-card img {
  display: block;
  width: 100%;
  height: 160px;
  object-fit: cover;
  transition: opacity 0.3s;
}
.related-card:hover img { opacity: 0.7; }
.related-card .related-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 12px;
  background: linear-gradient(to bottom, rgba(0,0,0,0) 0%, rgba(0,0,0,0.75) 100%);
  color: #fff;
}
.related-card .related-title a {
  color: #fff;
  font-size: 12px;
  font-weight: 800;
  text-transform: uppercase;
  line-height: 1.3;
  font-family: 'Roboto', sans-serif;
}
.related-card .related-title a:visited { color: #fff; }
.related-card .related-title a:hover { color: #ddd; }
.related-card .related-meta {
  font-size: 10px;
  color: #ccc;
  margin-top: 3px;
  font-family: 'Open Sans', sans-serif;
}
@media (max-width: 768px) {
  .related-grid { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 480px) {
  .related-grid { grid-template-columns: 1fr; }
}

/* Sidebar inject wrappers (for non-homepage sidebar sections placed outside b:if) */
.sidebar-inject-wrap { display: none; }
/* JS will move sections into .content-layout aside and show them */
.content-layout aside#sidebar-injected {
  width: 300px;
  min-width: 300px;
}
.content-layout aside#sidebar-injected .widget {
  margin-bottom: 20px;
  background: #fff;
  padding: 15px;
  border: 1px solid #eee;
}
@media (max-width: 992px) {
  .content-layout aside#sidebar-injected { width: 100%; min-width: 0; }
}

/* Utility */
.hidden { display: none; }
.invisible { visibility: hidden; }
.sr-only { position: absolute; width: 1px; height: 1px; clip: rect(0,0,0,0); overflow: hidden; }
.item-control { display: none; }
.clear { clear: both; }

