div.script:
(function(){
  var labels = [];
  var labelEls = document.querySelectorAll('.byline.post-labels a');
  for (var i = 0; i < labelEls.length; i++) {
    labels.push(labelEls[i].textContent.trim());
  }
  var label = labels[0] || '';
  if (label) {
    var s = document.createElement('script');
    s.src = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?max-results=20&orderby=published&alt=json-in-script&callback=relatedArticles';
    document.getElementsByTagName('head')[0].appendChild(s);
