    var s2 = document.createElement('script');
    s2.src = '/feeds/posts/default?max-results=20&orderby=published&alt=json-in-script&callback=relatedArticles';
    document.getElementsByTagName('head')[0].appendChild(s2);
  }
})();

body.script:
//
$(document).ready(function(){
  // Mobile menu
  if (typeof $.fn.slicknav === 'function') {
    $('#main-nav .nav-menu').slicknav({
      prependTo: '.topbar-nav .container',
      label: '',
      closedSymbol: '<i class="fa-solid fa-plus"></i>',
      openedSymbol: '<i class="fa-solid fa-minus"></i>'
    });
  }

  // Top search toggle
  $('#topSearchToggle').click(function(e){
    e.stopPropagation();
    $('#topSearchBox').toggleClass('active');
  });
  $(document).click(function(){ $('#topSearchBox').removeClass('active'); });
  $('#topSearchBox').click(function(e){ e.stopPropagation(); });

  // Back to top
  var $btt = $('#back-to-top');
  $btt.hide();
  $(window).scroll(function(){
    if ($(this).scrollTop() > 300) { $btt.fadeIn('slow'); }
    else { $btt.fadeOut('slow'); }
  });
  $btt.click(function(){ $('html, body').animate({scrollTop:0},'slow'); });

  // Auto-init new HTML widgets in cat_section_2 as funFashionGrid
  $('#cat_section_2 .widget.HTML').each(function(){
    var $w = $(this);
    // Skip if already initialized (has cat-ff- div with content)
    if ($w.find('.cat-ff-layout').length) return;
    // Find the widget content (label name)
    var $content = $w.find('.widget-content');
    if (!$content.length) return;
    var label = $.trim($content.text());
    if (!label) return;
    // Create a target container
    var tid = 'cat-ff-auto-' + $w.attr('id');
    var $title = $w.find('.title, h3, h2').first();
    var titleText = $title.length ? $title.text() : label;
    var html = '<div class="section-header"><h2 class="section-title">' + titleText + '</h2></div>';
    html += '<div id="' + tid + '"></div>';
    $content.html(html);
    // Load feed
    var s = document.createElement('script');
    var cbName = '_cff' + tid.replace(/-/g, '');
    window[cbName] = function(json) { funFashionGrid(json, tid); };
    s.src = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?max-results=6&orderby=published&alt=json-in-script&callback=' + cbName;
    document.getElementsByTagName('head')[0].appendChild(s);
  });
});
