//
(function(){
  var postBody = document.querySelector('.post-body');
  if (!postBody) return;
  // Check if custom share buttons already exist (from includable override)
  if (document.querySelector('.custom-share-buttons')) return;
  var url = encodeURIComponent(window.location.href);
  var title = encodeURIComponent(document.title);
  var html = '<div class="custom-share-buttons">' +
    '<span class="share-label">SHARE:</span>' +
    '<a class="share-btn share-fb" href="https://www.facebook.com/sharer/sharer.php?u=' + url + '" target="_blank" rel="noopener noreferrer" title="Share to Facebook" onclick="window.open(this.href,\'fb\',\'width=600,height=400\');return false;"><i class="fa-brands fa-facebook-f"></i></a>' +
    '<a class="share-btn share-tw" href="https://twitter.com/intent/tweet?url=' + url + '&text=' + title + '" target="_blank" rel="noopener noreferrer" title="Share to Twitter" onclick="window.open(this.href,\'tw\',\'width=600,height=400\');return false;"><i class="fa-brands fa-x-twitter"></i></a>' +
    '<a class="share-btn share-wa" href="https://api.whatsapp.com/send?text=' + title + ' ' + url + '" target="_blank" rel="noopener noreferrer" title="Share to WhatsApp"><i class="fa-brands fa-whatsapp"></i></a>' +
    '<a class="share-btn share-tg" href="https://t.me/share/url?url=' + url + '&text=' + title + '" target="_blank" rel="noopener noreferrer" title="Share to Telegram" onclick="window.open(this.href,\'tg\',\'width=600,height=400\');return false;"><i class="fa-brands fa-telegram"></i></a>' +
    '</div>';
  postBody.insertAdjacentHTML('afterend', html);
})();
//

//
(function(){
  // Auto-populate author widget from post metadata
  var authorEl = document.querySelector('.post-author-name, .post-author a, .fn.author, .byline.post-author a, span.fn, .post-header .fn');
  var authorName = '';
  if (authorEl) {
    authorName = authorEl.textContent.trim();
  }
  if (!authorName) {
    // Try from Blogger's structured data
    var metaAuthor = document.querySelector('meta[name="author"]');
    if (metaAuthor) authorName = metaAuthor.getAttribute('content');
  }
  if (!authorName) {
    // Fallback: look for author in post byline area
    var bylines = document.querySelectorAll('.post-header .byline');
    for (var i = 0; i < bylines.length; i++) {
      var txt = bylines[i].textContent.trim();
      if (txt && !txt.match(/^\d/) && !txt.match(/comment/i)) {
        authorName = txt;
        break;
      }
    }
  }
  var nameEl = document.getElementById('auto-author-name');
  var avatarEl = document.getElementById('auto-author-avatar');
  if (nameEl && authorName) {
    nameEl.textContent = authorName;
  } else if (nameEl) {
    nameEl.textContent = 'Author';
  }
  if (avatarEl && authorName) {
    var initial = authorName.charAt(0).toUpperCase();
    var avatarDiv = document.createElement('div');
    avatarDiv.style.cssText = 'width:70px;height:70px;border-radius:50%;background:#2C91E1;color:#fff;display:inline-flex;align-items:center;justify-content:center;font-size:28px;font-weight:700;font-family:Roboto,sans-serif;margin-bottom:5px;';
    avatarDiv.textContent = initial;
    avatarEl.innerHTML = '';
    avatarEl.appendChild(avatarDiv);
  }

  // JS-based breadcrumb (ensure it shows above the post title)
  var mainContent = document.getElementById('main-content');
  if (!mainContent) return;
  // Remove any existing Blogger breadcrumb nav elements
  var navs = mainContent.querySelectorAll('nav');
  for (var n = 0; n < navs.length; n++) {
    navs[n].style.display = 'none';
  }
  // Also check blog-posts level
  var blogPosts = document.querySelector('.blog-posts');
  if (blogPosts) {
    var bpNavs = blogPosts.querySelectorAll('nav');
    for (var bn = 0; bn < bpNavs.length; bn++) {
      bpNavs[bn].style.display = 'none';
    }
  }
  // Check if custom breadcrumb already exists (from includable)
  if (document.querySelector('.custom-breadcrumb')) return;
  // Build breadcrumb from post labels
  var labels = document.querySelectorAll('.byline.post-labels a');
  var crumb = '<div class="custom-breadcrumb">';
  crumb += '<a href="/">Home</a>';
  if (labels.length > 0) {
    crumb += '<span class="sep">&gt;</span>';
    crumb += '<a href="' + safeUrl(labels[0].href) + '">' + escapeHtml(labels[0].textContent.trim()) + '</a>';
  }
  crumb += '<span class="sep">&gt;</span>';
  var postTitle = document.querySelector('.post-title');
  var titleText = postTitle ? postTitle.textContent.trim() : document.title;
  crumb += '<span class="current">' + escapeHtml(titleText) + '</span>';
  crumb += '</div>';
  // Insert before the first post
  var firstPost = mainContent.querySelector('.blog-posts, .post-outer-container, .post-outer');
  if (firstPost) {
    firstPost.insertAdjacentHTML('beforebegin', crumb);
  } else {
    mainContent.insertAdjacentHTML('afterbegin', crumb);
  }
})();
